async (params, browser) => {
  // Open matches
  await browser.open('https://tinder.com/app/matches')

  // Wait for matches
  await browser.waitForSelector('[class*="matchList"], a[href*="/messages/"]', 15000)

  // Let matches load
  await browser.wait(2000)

  // Find match
  const find_match = await browser.evaluate(`const links = document.querySelectorAll('a[href*="/app/messages/"], [class*="matchList"] a, [class*="messageListItem"] a, a[href*="/messages/"]'); for (const link of links) { if (link.textContent?.toLowerCase()?.includes('' + params.match_name + ''.toLowerCase())) { link.click(); return { found: true }; } } return { found: false, message: 'Match not found' };`)

  // Wait for chat
  await browser.wait(2000)

  // Type message
  const type_msg = await browser.evaluate(`const input = document.querySelector('textarea, [class*="sendMessageForm__input"], [contenteditable="true"], input[type="text"]'); if (!input) return { success: false, message: 'Message input not found' }; input.focus(); document.execCommand('insertText', false, '' + params.message + ''); input.dispatchEvent(new Event('input', { bubbles: true })); return { typed: true };`)

  await browser.wait(500)

  // Send message
  const result = await browser.evaluate(`const sendBtn = document.querySelector('button[type="submit"], [class*="send"], [aria-label*="Send"]'); if (sendBtn) { sendBtn.click(); return { success: true }; } return { success: false, message: 'Send button not found' };`)

  return result
}
